{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a constrained packing/layout optimization problem. It requires translating a graph-based connectivity structure into a 2D grid layout while satisfying adjacency constraints and maximizing empty space.",
  "helpers": [
    {
      "label": "graph_representation_extractor",
      "instructions": "Parse the input city map to extract a graph where each node represents a unique color/region and each edge represents a color-adjacency relation. Identify the set of required adjacencies that must be preserved in the 50x50 grid."
    },
    {
      "label": "connectivity_constraint_analyzer",
      "instructions": "Analyze the extracted graph for connectivity properties (e.g., degree of nodes, articulation points, or cycles). Determine the minimum number of cells required to represent each color region such that all required adjacencies are physically possible on a 2D grid."
    },
    {
      "label": "grid_layout_optimizer",
      "instructions": "Implement a placement algorithm (e.g., simulated annealing, constraint programming, or a greedy growth algorithm) to map the color regions onto a 50x50 grid. The objective is to place the required color cells such that all adjacency edges from the graph are satisfied by orthogonal neighbors, while minimizing the total number of cells occupied by colors to maximize empty space (E)."
    },
    {
      "label": "constraint_verifier",
      "instructions": "Given a proposed 50x50 grid layout, verify that: 1) Every color from the original map is present. 2) All required color-adjacency relations are satisfied by at least one pair of adjacent cells. 3) No illegal adjacencies are created that violate the original topology (if the problem implies strict topological equivalence). 4) The grid dimensions are exactly 50x50."
    }
  ],
  "synthesis_brief": "Combine the graph data and connectivity analysis to inform the layout optimizer. The optimizer will produce a candidate grid. The verifier will check the candidate against the original constraints. If valid, calculate E (total cells - occupied cells) and return the grid as the FINAL_ANSWER along with the calculated score (E + 1)."
}
```

